{
  "name": "Texas Simplified Application Project (TSAP) for SNAP",
  "eligibility": {
    "age": 60,
    "income_limits": "Follows standard SNAP rules in Texas: gross income at or below 165% of the federal poverty level (FPL). Exact dollar amounts vary by household size and are updated annually; consult current HHS Texas SNAP charts as specific tables not detailed in sources. Applies to households where all members are age 60+ or disabled.[1][2][4]",
    "asset_limits": "Not specified in sources; follows standard SNAP asset rules unless simplified for this group. No unique exemptions detailed.[1]",
    "other_requirements": ["All household members must be age 60 or older, or living with disabilities (households where all members are elderly or disabled).[1][2][4]"]
  },
  "benefits": {
    "type": "financial",
    "value": "SNAP food benefits loaded on an EBT card for purchasing food at grocery stores, qualifying online retailers, and farmers' markets. Award amount determined upon approval; specific dollar values vary by household income, size, and eligibility (no fixed amounts listed).[1]",
    "varies_by": "household_size"
  },
  "application": {
    "methods": [
      "Phone: Call 844.583.1500 to reach a local assister anywhere in Texas.[2]",
      "Mail: Download and complete the 'Texas Simplified SNAP Application' (paper form for elderly/disabled households), gather documentation, mail via certified mail.[1]",
      "Online: Not explicitly detailed for TSAP; standard SNAP online application available via YourTexasBenefits.com (implied).[1]"
    ],
    "processing_time": "Application completion: 30-45 minutes. Follow-up questions/processing: up to 30 days. Interview and decision: within 6-9 weeks.[1]",
    "waitlist": null,
    "forms": ["Texas Simplified SNAP Application (paper form for households age 60+ or disabled).[1]"],
    "documents": ["Related documentation to support eligibility (e.g., proof of age, disability, income); specific items requested via follow-up letter from Texas Health and Human Services Commission.[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Assisters available statewide via phone; no specific regional differences in program rules, providers, or wait times noted.[2]",
    "offices_or_providers": ["Local assisters reachable by calling 844.583.1500.[2]"]
  },
  "official_source": "https://www.hhs.texas.gov/services/food/snap-food-benefits/texas-simplified-application-project-tsap-snap-food-benefits[3]",
  "gotchas": [
    "Only for households where ALL members are age 60+ or disabled; mixed households may not qualify for simplified process.[1][4]",
    "Must confirm eligibility for simplified paper application before using it.[1]",
    "Processing can take up to 9 weeks; expect phone calls, letters for more info, and an interview.[1]",
    "Benefits are SNAP-specific (food only), not cash or other services.[1][3]"
  ],
  "data_shape_notes": "Simplified application and assistance targeted exclusively at elderly (60+) or disabled households; statewide with phone-based local assisters; follows core SNAP income rules (165% FPL) but streamlined process.[1][2][4]"
}

{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Varies by funding source: LIHEAP WAP at 150% Federal Poverty Level (FPL), DOE WAP at 200% FPL. For 2026 (effective Jan 27, 2025):|Persons in Family/Household|LIHEAP WAP (150% FPL)|DOE WAP (200% FPL)|\n|--|--|--|\n|1|$23,940|$31,920|\n|2|$32,460|$43,280|\n|3|$40,980|$54,640|\n|4|$49,500|$66,000|\n|5|$58,020|$77,360|\n|6|$66,540|$88,720|\n|7|$75,060|$100,080|\n|8|$83,580|$111,440|\n|More than 8|Add $8,250/person|Add $11,000/person|. Income based on all sources for household members 18+ over last 30 days, annualized[3][4].",
    "asset_limits": "No asset limits mentioned across sources.",
    "other_requirements": ["Must reside in a service area covered by a subrecipient (county-specific)", "Proof of income for last 30 days for all 18+ household members", "Proof of identity and residency/citizenship for all household members", "Homeowner or renter with landlord permission", "Services typically once every 15 years[6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free installation of weatherization materials including energy audits, sealing air leaks, insulation, inefficient appliance repairs/replacements, minor home repairs for health/safety, and energy education. Prioritizes energy efficiency and safety; no direct cash[1][3][5][6].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local subrecipient agency (full list at TDHCA site)", "Online portals (e.g., Travis County Application Portal)", "Phone: Local subrecipient or 211 (United Way HELPLINE for Harris County)", "Downloadable forms (e.g., Dallas County WAP Application)", "In-person/mail to local offices (e.g., Dallas County Health and Human Services, 2377 N. Stemmons Freeway, Dallas, TX 75207)"],
    "processing_time": "Not specified; involves pre-screening, full application, home audit, then work scheduling.",
    "waitlist": "Likely due to funding limits; varies by subrecipient and demand.",
    "forms": ["WAP Application (Dallas County)", "Landlord or Homeowner Agreement (Travis County)", "General application via subrecipients"],
    "documents": ["Government-issued photo ID (all members)", "Proof of ALL household income last 30 days (pay stubs, SS award letters, unemployment, pensions, etc.)", "SS cards/numbers", "Proof of citizenship/residency (passport, birth certificate, etc.)", "Current electric/gas bill (with meter # if Reliant)", "Landlord permission if renter"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered county-by-county via  subrecipients covering all 254 Texas counties; must contact local provider.",
    "regional_variations": "Different subrecipients per region (e.g., Travis County HHS, BakerRipley in Harris, SPCAA in 15 South Plains counties, Dallas County DCHHS); application processes, contacts, and wait times vary[1][2][3][5][6].",
    "offices_or_providers": ["Full list of subrecipients: TDHCA PDF", "Examples: Travis County HHS, BakerRipley (Harris), SPCAA (South Plains), Dallas County DCHHS, CACOST"]
  },
  "official_source": "https://www.tdhca.texas.gov/weatherization-assistance-program",
  "gotchas": ["County-specific: Not statewide direct apply; find your subrecipient first.", "Two tiers (LIHEAP 150% FPL vs DOE 200% FPL); check which applies.", "Proof of income for last 30 days from ALL adult household members required.", "Renter needs landlord agreement; services once every 15 years.", "Funding limited, potential waitlists; no assets test but strict income proof.", "Elderly priority often via vulnerable categories, but no strict age cutoff."],
  "data_shape_notes": "County-administered via subrecipients covering all TX; dual income tiers (150%/200% FPL); 30-day income proof; free services post-audit; elderly qualify if low-income/household vulnerable."
}

{
  "name": "Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income limits or tables identified for this program in Texas; related programs like Community Care for the Aged and Disabled (CCAD) limit income to no more than three times the Supplemental Security Income benefit or three times the Federal Poverty Level, with assets up to $5,000 for individuals or $6,000 for couples. Caregiver assistance programs exclude those with family income >300% of federal poverty guidelines.",
    "asset_limits": "Not specified for this program; in CCAD, countable assets ≤$2,000-$5,000 (individual) or $6,000 (couple), exempting home, one vehicle, household goods, personal effects, wedding/engagement rings, and irrevocable prepaid funeral plan.",
    "other_requirements": ["Program targets caregivers of elderly (typically 60+) or disabled adults; exact requirements vary by local Area Agency on Aging (AAA); care recipient often must be at risk of nursing home placement and not receiving duplicate services."]
  },
  "benefits": {
    "type": "service",
    "value": "Specific services include respite care, caregiver training, counseling, support groups, and supplemental services (e.g., assistive devices, home modifications); no fixed dollar amounts or hours statewide; may include limited cash assistance in related programs.",
    "varies_by": "region"
  },
 "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) via Texas Health and Human Services at 1-800-252-9240 or hhs.texas.gov/services/aging; in-person at local AAA offices; phone-based screening; no specific online form or statewide URL identified for direct application."],
    "processing_time": "Not specified; varies regionally.",
    "waitlist": "Possible waitlists due to funding limits, varying by region.",
    "forms": ["No specific form name/number identified; screening/assessment forms used by local AAAs."],
    "documents": ["Proof of income/residency for care recipient, medical/functional assessment of needs, ID; specifics determined during intake."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through 28 local Area Agencies on Aging covering all Texas counties.",
    "regional_variations": "Services, availability, wait times, and providers differ by AAA region; funding and prioritization vary locally.",
    "offices_or_providers": ["Local Area Agencies on Aging; find via hhs.texas.gov/services/aging/area-agencies-aging"]
  },
  "official_source": "https://www.hhs.texas.gov/services/aging/family-caregiver-support",
  "gotchas": ["Not a paid caregiver program—focuses on support services like respite, not direct wages (unlike STAR+PLUS Medicaid waiver or VA PCAFC); eligibility assessed for care recipient's needs, not caregiver income primarily; funding-limited with regional waitlists; often confused with Medicaid consumer-directed programs where family can be paid.", "Must contact local AAA as no centralized application.", "Duplicate services from other programs disqualify."],
  "data_shape_notes": "Administered regionally via 28 AAAs with no uniform statewide income/asset tables or fixed benefits; services scale by local funding and priority (e.g., caregivers of 60+); no direct pay to caregivers, distinguishing from Medicaid self-direction programs."
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are set by federal poverty guidelines (e.g., consult current HHS poverty guidelines table for precise figures; not specified in static dollar amounts in sources but consistently capped at 125% FPL).[2][3]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "Low employment prospects", "Priority for: age 65+, veterans, qualified spouses, individuals with disabilities, limited English proficiency, rural residents, homeless/at risk of homelessness, low literacy, failed to find work after American Job Center services, or recent incarceration (within last 5 years). Local providers make final eligibility determination."][1][2]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time work (average 20 hours/week) at nonprofit or public agencies (e.g., schools, hospitals, senior centers); paid highest of federal/state/local minimum wage; on-the-job training in skills like computers, typing, healthcare; job placement assistance; support classes (reading, writing, math, GED); career counseling, resume workshops via Workforce Solutions.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local SCSEP provider (e.g., AARP Foundation locator: my.aarpfoundation.org/locator/scsep/; TWC: twc.texas.gov/programs/senior-community-service-employment; MET, Inc. for specific counties: (832) 432-7170, labanzat@metinc.org; Workforce Solutions offices; Area Agencies on Aging.", "In-person at Workforce Solutions offices.", "Phone or email to county-specific providers."],
    "processing_time": "Not specified.",
    "waitlist": "Possible due to funding limits and priority groups; varies by local provider.",
    "forms": ["No specific form names/numbers listed; eligibility determined by local providers."],
    "documents": ["Proof of age, income (to verify ≤125% FPL), unemployment status, and priority group documentation if applicable (e.g., veteran status, disability proof). Prepare tax returns, pay stubs, benefit statements."]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Operates in 82 Texas counties via TWC and AARP Foundation; other counties via partners like MET, Inc. (specific list includes Anderson, Angelina, etc.). Not all 254 counties covered.",
    "regional_variations": "Administered by different local providers (e.g., MET, Inc. for many counties); eligibility finalized by local providers; services via 28 Local Workforce Development Boards and Area Agencies on Aging; wait times and availability vary by county/provider.",
    "offices_or_providers": ["Texas Workforce Commission (TWC)", "AARP Foundation", "MET, Inc. (e.g., (832) 432-7170 for listed counties)", "Workforce Solutions offices", "Area Agencies on Aging"]
  },
  "official_source": "https://www.twc.texas.gov/programs/senior-community-service-employment",
  "gotchas": ["Not available statewide—check county coverage first.", "Must be unemployed; not for current workers.", "Priority groups get preference, leading to waitlists for others.", "Local providers decide eligibility—federal rules apply but final call is local.", "Temporary bridge program aimed at unsubsidized employment, not long-term.", "No asset test, but strict income cap at 125% FPL.", "Participants work at host agencies, not direct hire by program."],
  "data_shape_notes": "County-restricted (82+ counties via TWC/AARP, others via partners like MET); priority tiers heavily influence access; no fixed statewide processing time or forms; benefits are work-based training at min wage, not cash aid; varies by local Workforce Boards and providers."
}

{
  "name": "Legal Aid for Seniors (via Area Agencies on Aging/Legal Hotlines)",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific statewide income limits stated; priority given to low-income seniors, but services generally available to all aged 60+ without strict dollar thresholds. Varies by AAA; some prioritize low-income or underrepresented groups[1][2][6].",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Texas resident", "Live in the service area of a specific AAA (covers all 254 counties via 28 AAAs)", "Priority for low-income, rural residents, disabled, dementia patients, limited English speakers, or caregivers[1][2][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Legal assistance including advice/counseling (phone or in-person), document preparation for entitlements/health care/rights/housing, representation/advocacy in appeals or court; benefits counseling for Medicare/Medicaid/Social Security; money management, representative payee, guardianship; ombudsman advocacy for nursing/assisted living facilities[1][4][5][6]. No specific dollar amounts or hours stated.",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Phone: Call local AAA (examples: Houston-Galveston (281) 633-0519[3], Concho Valley (325) 223-5704[3], Tarrant County (817) 258-8000[3], East Texas (903) 218-6500[3])", "In-person: Local AAA offices (e.g., North Central Texas AAA serves specific counties[8]; full list via Texas Association of Regional Councils[4])", "Website: Local AAA sites (e.g., aaact.org for Central Texas[7], easttexasaaa.org[5], nctcog.org/aging-services[8])"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not mentioned; may vary by region.",
    "forms": ["No specific form names/numbers identified; intake via phone or in-person."],
    "documents": ["Not explicitly listed; prepare proof of age, residency, Medicare status if applicable[1][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "All 254 Texas counties covered by 28 regional AAAs; must contact local AAA for service area (e.g., Houston-Galveston: Austin/Brazoria/etc. counties[2]; North Central: Collin/Denton/etc.[8])[1][4][8]",
    "regional_variations": "Services delivered by 28 distinct AAAs with local offices/providers; priority groups, exact services, and contact info vary by region (e.g., East Texas emphasizes case management[5]; South Texas specifies legal services categories[6])[2][3][4][5][6][7][8]",
    "offices_or_providers": ["28 AAAs including Houston-Galveston, Concho Valley, Legal Aid of NorthWest Texas (partner), Area Agency on Aging of Central Texas, Tarrant County AAA, North Central Texas AAA, East Texas AAA, etc.[1][3][4]"]
  },
  "official_source": "https://texaslawhelp.org/article/area-agencies-on-aging-a-place-to-get-help (primary overview); https://txregionalcouncil.org/regional-programs/health-and-human-services/area-agencies-on-aging/ (AAA list)",
  "gotchas": ["Not a single centralized program—must identify and contact the specific regional AAA for your county[1][4]", "No strict income test, but low-income get priority; not full legal representation for all cases[2][6]", "Under-60 services limited to certain Medicare-eligible disabled via CMS funding[6]", "Focuses on elder-specific issues like benefits/ombudsman, not general legal aid[1][4]"],
  "data_shape_notes": "Decentralized across 28 regional AAAs covering all counties; no uniform income/asset table; services and priorities vary by local AAA; priority-based rather than strict eligibility"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all residents regardless of financial status[7][9].",
    "asset_limits": "No asset limits or tests; no financial eligibility requirements apply[7].",
    "other_requirements": ["Must be a resident of a nursing facility or assisted living facility in Texas[7][4][9]", "Services also extend to certain caregivers and family members of persons 60 years or older[2]", "No age requirement for residents, though focused on older adults[1][3][7]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for residents' rights, investigation and resolution of complaints about quality of care and life, protection from abuse/neglect, assistance with grievances, access to records, participation in hearings, ensuring rights like dignity, privacy, medical information, freedom from restraints, and non-discrimination[4][7][9]; provided by trained volunteer or paid ombudsmen independent of facilities[3][7]. No specific dollar amounts, hours, or fixed quantities.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-252-2412 to speak with an LTC ombudsman in your area[7]", "Email: contact form via ltco.texas.gov[7]", "In-person or local: Find an LTC Ombudsman in your area via ltco.texas.gov[7]", "No formal application or forms required for receiving services; contact directly for assistance[7]"],
    "processing_time": "Immediate response upon contact; no formal processing as it's complaint-driven advocacy[7][9].",
    "waitlist": null,
    "forms": ["No specific forms for recipients; HHSC form for program submissions (not public-facing)[2]"],
    "documents": ["No documents needed to request services; provide details of concerns or facility for advocacy[7][9]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available to residents in nursing facilities and assisted living facilities statewide[7][9]; separate program for state supported living centers[7].",
    "regional_variations": "Administered locally by different agencies (e.g., Cizik School of Nursing/UTHealth Houston with Harris County Area Agency on Aging in Harris County[3]; Texoma Council of Governments in Texoma Region[4]; East Texas AAA in East Texas[9]; H-GAC in relevant area[1]); same core services but local offices handle delivery[1][3][4][9].",
    "offices_or_providers": ["Local programs via ltco.texas.gov 'Find an LTC Ombudsman'[7]"]
  },
  "official_source": "https://ltco.texas.gov[7]",
  "gotchas": ["Not a service provider or eligibility-determining program—purely advocacy for existing long-term care residents, not for admission or financial aid[2][5][7]", "Volunteers must pass criminal checks and conflict screenings; program independent of facilities, Medicaid eligibility, or protective services[1][2][3]", "Confidentiality applies to all complaints[5]", "Does not provide direct care, housing, or benefits—focuses on rights protection and complaint resolution[4][7]", "Separate ombudsman for developmental disability state living centers[7]"],
  "data_shape_notes": "no income test; advocacy-only for residents of nursing homes/assisted living facilities; delivered via statewide network of local independent programs with volunteers; complaint-driven, no formal eligibility/application process"
}
